body.script:
const tools = [
  {name: "Age Calculator", url:"/calculators/age-calculator.html", description:"Calculate your exact age in years, months, and days. Perfect for knowing your precise age or planning age-related events."},
  {name: "Percentage Calculator", url:"/calculators/percentage-calculator.html", description:"Quickly calculate percentages, percentage increase/decrease, and find what percentage one number is of another."},
  {name: "Date Difference Calculator", url:"/calculators/date-difference-calculator.html", description:"Find the exact difference between two dates in years, months, days, hours, and minutes with precision."},
  {name: "Loan EMI Calculator", url:"/calculators/loan-emi-calculator.html", description:"Calculate your monthly loan EMI payments with detailed breakup of principal and interest amounts."},
  {name: "Simple Interest Calculator", url:"/calculators/simple-interest-calculator.html", description:"Compute simple interest on your investments or loans with easy-to-understand results and formulas."},
  {name: "Compound Interest Calculator", url:"/calculators/compound-interest-calculator.html", description:"Calculate compound interest with various compounding frequencies to plan your investments effectively."},
  {name: "Profit & Loss Calculator", url:"/calculators/profit-loss-calculator.html", description:"Determine profit or loss percentage on your business transactions and investments instantly."},
  {name: "Discount Calculator", url:"/calculators/discount-calculator.html", description:"Calculate discounted prices, savings amount, and final price after applying discount percentages."},
  {name: "GPA Calculator", url:"/calculators/gpa-calculator.html", description:"Calculate your Grade Point Average (GPA) for academic performance tracking and college applications."},
  {name: "Number to Words Converter", url:"/calculators/number-to-words-calculator.html", description:"Convert any number into words format, perfect for check writing and formal documentation."},
  {name: "CV Maker", url:"/tools/cv-maker.html", description:"Create a professional CV in minutes with our easy-to-use builder. Preview in real-time and download as PDF."},
  {name: "Invoice Maker", url:"/tools/invoice-maker.html", description:"Generate professional invoices for your business in seconds. Customizable templates, PDF export, and easy branding."},
  {name: "AI Content Humanizer", url:"/tools/ai-content-humanizer.html", description:"Make your AI-generated text sound more human. Adjust tone, style, and flow to create high-quality, engaging content."}
];

function formatDate(d) {
    return d.toISOString().split('T')[0];
}

let xml = '\n';
xml += '\n';

tools.forEach(tool => {
    xml += '  \n';
    xml += `    https://90storezon.com${tool.url}\n`;
    xml += `    ${formatDate(new Date())}\n`;
    xml += '    monthly\n';
    xml += '    0.9\n';
    xml += `    ${tool.name}\n`;
    xml += `    ${tool.description}\n`;
    xml += '  \n';
});

xml += '';

console.log(xml);  // Copy the output and save as sitemap.xml
alert("Sitemap with Names and Descriptions generated! Check console.");
